import{_ as a,o as t,c as i,ag as s}from"./chunks/framework.CbQjVMS6.js";const o="/assets/name.BwlrE9Zh.png",m=JSON.parse('{"title":"Compile Plain Text TI Basic to 8XP","description":"","frontmatter":{},"headers":[],"relativePath":"features/compile-to-8xp.md","filePath":"features/compile-to-8xp.md","lastUpdated":1774323326000}'),r={name:"features/compile-to-8xp.md"};function n(p,e,l,h,c,d){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="compile-plain-text-ti-basic-to-8xp" tabindex="-1">Compile Plain Text TI Basic to 8XP <a class="header-anchor" href="#compile-plain-text-ti-basic-to-8xp" aria-label="Permalink to &quot;Compile Plain Text TI Basic to 8XP&quot;">​</a></h1><p>Powerpack understands both binary 8XP programs (such as those written in TI Connect CE) and plain text TI Basic. You can write your programs in whichever format you prefer.</p><p>You might like to use plain text format for writing programs in <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">VSCode</a> or your favorite text editor. With VSCode you will have access to AI coding assistants like <a href="https://github.com/features/copilot" target="_blank" rel="noreferrer">Copilot</a>.</p><p>When you run <code>Powerpack.exe</code> on your program, it will detect the format, process the file, and compile it into 8XP binary format, ready for loading into an emulator like WabbitEmu or for transferring to your calculator.</p><p>Both of these commands will work the same:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">powerpack MYPROG.8xp</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">powerpack MyPlainTextCode.8xppp</span></span></code></pre></div><h2 id="_8xppp-extension" tabindex="-1">8xppp extension <a class="header-anchor" href="#_8xppp-extension" aria-label="Permalink to &quot;8xppp extension&quot;">​</a></h2><p>While any filename extension will work for basic compilation, if you want to code in plain text format and make use of the <a href="/features/autorun">auto-run</a> feature, be sure to name your file with an <code>.8xppp</code> extension so that it’s detected. (8xppp stands for “8XP Powerpack”.)</p><p>Future versions of Powerpack will allow you to customize this and use whichever extension you prefer.</p><h2 id="program-name" tabindex="-1">Program name <a class="header-anchor" href="#program-name" aria-label="Permalink to &quot;Program name&quot;">​</a></h2><p>One key difference between the 8XP binary format and using a plain text format is that the 8XP binary format allows you to specify the 8-character name of the program that is shown on your calculator — and this doesn’t have to match the filename.</p><p><img src="`+o+`" alt="" width="450"></p><p>However, when compiling from <em>plain text format</em>, the name of the program will be determined from the source code filename by taking the first 8 characters and converting them to uppercase.</p><p>A future version of Powerpack may allow customization of this filename, but that is how it works for now.</p><h2 id="ti-basic-syntax" tabindex="-1">TI Basic syntax <a class="header-anchor" href="#ti-basic-syntax" aria-label="Permalink to &quot;TI Basic syntax&quot;">​</a></h2><p>The syntax for writing programs in plain text is designed to match the syntax as used in TI Connect CE as closely as possible. There may be a few minor situations where the syntax is different, and we will aim to document those here.</p><p>This requires the use of some special characters which are not easily typed from your keyboard, including:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">→    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// The STO→ character</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">­-    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// The negative symbol, different from a minus/hyphen</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">≠    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Not equal</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">≥    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Greater than or equal</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">≤    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Less than or equal</span></span></code></pre></div><p><a href="/keyboard-shortcuts">Keyboard shortcuts</a> help greatly in working with these characters.</p><p>If you’re coding in TI Connect CE, these characters are all available from the list in the left pane, which requires no extra software.</p><p>If you’re using another editor, you might like to create <a href="https://code.visualstudio.com/docs/editing/userdefinedsnippets" target="_blank" rel="noreferrer">snippets</a> for these extra characters or set up keyboard shortcuts using something like Espanso. <a href="/keyboard-shortcuts">Read our guide on keyboard shortcuts</a>.</p>`,21)])])}const f=a(r,[["render",n]]);export{m as __pageData,f as default};
